// modules/tasks/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Handles task creation, assignment, and management.',

  dependencies: { modules: [] },

  exposes: {
    routes: [
      { method: 'POST', path: '/tasks/create', auth: true },
      { method: 'GET',  path: '/tasks/list',   auth: true },
      { method: 'PUT',  path: '/tasks/assign', auth: true },
      { method: 'DELETE', path: '/tasks/delete', auth: true },
    ],
    functions: ['createTask', 'listTasks', 'assignTask', 'deleteTask'],
    types: ['Task', 'AssignmentError'],
  },

  sideEffects: [
    'writes to: tasks table',
    'writes to: assignments table',
  ],

  invariants: [
    'A task must always be assigned to exactly one user',
    'Archived tasks must never be returned as active',
    'Deleting a task must remove all related assignments',
  ],
});

// modules/tasks/lib/archive.ts
import { query } from '../db';
import { Task, AssignmentError } from '../../lib/types';

export async function archiveFinishedTasks(): Promise<void> {
  const thirtyDaysAgo = new Date();
  thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

  try {
    await query(`
      BEGIN;

      INSERT INTO archived_tasks (task_id, title, description, due_date, created_at, updated_at)
      SELECT task_id, title, description, due_date, created_at, updated_at
      FROM tasks
      WHERE status = 'completed' AND completed_at < $1;

      DELETE FROM tasks
      WHERE status = 'completed' AND completed_at < $1;

      COMMIT;
    `, [thirtyDaysAgo]);
  } catch (error) {
    await query('ROLLBACK');
    throw new AssignmentError('Failed to archive finished tasks', error);
  }
}

// modules/tasks/routes/archive.ts
import { Router, Request, Response } from 'bun';
import { requireUser } from '../../lib/auth';
import { archiveFinishedTasks } from '../lib/archive';

const router = new Router();

router.post('/tasks/archive', async (req: Request, res: Response) => {
  try {
    await requireUser(req);
    await archiveFinishedTasks();
    res.status(204).send();
  } catch (error) {
    if (error instanceof AssignmentError) {
      res.status(400).json({ error: error.message });
    } else {
      res.status(500).json({ error: 'Internal server error' });
    }
  }
});

export default router;

// modules/tasks/lib/queries.ts
import { query } from '../db';
import { Task, AssignmentError } from '../../lib/types';

export async function createTask(task: Task): Promise<Task> {
  try {
    const result = await query(`
      INSERT INTO tasks (title, description, due_date, created_at, updated_at)
      VALUES ($1, $2, $3, NOW(), NOW())
      RETURNING *;
    `, [task.title, task.description, task.due_date]);

    return result.rows[0];
  } catch (error) {
    throw new AssignmentError('Failed to create task', error);
  }
}

export async function listTasks(): Promise<Task[]> {
  try {
    const result = await query(`
      SELECT * FROM tasks;
    `);

    return result.rows;
  } catch (error) {
    throw new AssignmentError('Failed to list tasks', error);
  }
}

export async function assignTask(taskId: number, userId: number): Promise<void> {
  try {
    await query(`
      INSERT INTO assignments (task_id, user_id)
      VALUES ($1, $2);
    `, [taskId, userId]);
  } catch (error) {
    throw new AssignmentError('Failed to assign task', error);
  }
}

export async function deleteTask(taskId: number): Promise<void> {
  try {
    await query(`
      DELETE FROM assignments
      WHERE task_id = $1;

      DELETE FROM tasks
      WHERE task_id = $1;
    `, [taskId]);
  } catch (error) {
    throw new AssignmentError('Failed to delete task', error);
  }
}

// modules/tasks/lib/types.ts
import { Result, ok, err } from '../../lib/result';

export interface Task {
  task_id: number;
  title: string;
  description: string;
  due_date: Date;
  created_at: Date;
  updated_at: Date;
  status: 'pending' | 'completed';
  completed_at?: Date;
}

export class AssignmentError extends Error {
  constructor(message: string, cause?: Error) {
    super(message);
    this.name = 'AssignmentError';
    if (cause) {
      this.cause = cause;
    }
  }
}

